import subprocess
import shlex

def executeCommand():
    cmd = input("Enter command: ")
    if not cmd.strip():
        return
    parts = shlex.split(cmd)
    if not parts:
        return
    allowed_commands = {'ls', 'pwd', 'echo'}
    if parts[0] not in allowed_commands:
        return
    subprocess.run(parts, check=True)

